def update_all_previews(apps, schema_editor):
    Book = apps.get_model('books', 'Book')
    for title, text in PREVIEW_DATA.items():
        book = Book.objects.filter(title=title).first()
        if book:
            book.preview_text = text
            book.save()


class Migration(migrations.Migration):

    dependencies = [
        ('books', '0005_update_vishnevyy_sad_preview'),
    ]

    operations = [
        migrations.RunPython(update_all_previews, migrations.RunPython.noop),
    ]
